import{_ as e,c as o,o as a,a2 as r}from"./chunks/framework.DdOM6S6U.js";const f=JSON.parse('{"title":"Configuration System","description":"","frontmatter":{"sidebarPos":7,"sidebarTitle":"Config"},"headers":[],"relativePath":"system-reference/config.md","filePath":"system-reference/config.md","lastUpdated":null}'),t={name:"system-reference/config.md"},i=r('<h1 id="configuration-system" tabindex="-1">Configuration System <a class="header-anchor" href="#configuration-system" aria-label="Permalink to &quot;Configuration System&quot;">​</a></h1><p>Modularity uses a layered configuration system. Understanding the layers helps when customizing or debugging.</p><h2 id="configuration-layers" tabindex="-1">Configuration Layers <a class="header-anchor" href="#configuration-layers" aria-label="Permalink to &quot;Configuration Layers&quot;">​</a></h2><h3 id="_1-merges-package-defaults" tabindex="-1">1. merges (Package Defaults) <a class="header-anchor" href="#_1-merges-package-defaults" aria-label="Permalink to &quot;1. merges (Package Defaults)&quot;">​</a></h3><p><strong>Location</strong>: <code>config/merges/*.php</code><br><strong>Loaded</strong>: At bootstrap (BaseServiceProvider::registerBaseConfigs)<br><strong>Key</strong>: <code>modularity.{filename}</code> (e.g. <code>modularity.services</code>, <code>modularity.roles</code>)</p><p>Package defaults that do not depend on the translator. Merged recursively with <code>array_merge_recursive_preserve()</code>.</p><p><strong>Files</strong>: api, cache, composer, default_form_action, default_form_attributes, default_header, default_input, default_table_action, default_table_attributes, enabled, file_library, glide, imgix, input_types, laravel-relationship-map, mail, media_library, notifications, paths, payment, schemas, services, stubs, tables, traits</p><h3 id="_2-defers-localized-config" tabindex="-1">2. defers (Localized Config) <a class="header-anchor" href="#_2-defers-localized-config" aria-label="Permalink to &quot;2. defers (Localized Config)&quot;">​</a></h3><p><strong>Location</strong>: <code>config/defers/*.php</code><br><strong>Loaded</strong>: Per request via <code>LoadLocalizedConfig</code> middleware (runs in <code>modularity.core</code> group)<br><strong>Key</strong>: <code>modularity.{filename}</code></p><p>Config that needs the translator (e.g. <code>__()</code>, <code>___()</code>). Loaded after the translator is available.</p><p><strong>Files</strong>: auth_component, auth_pages, form_drafts, navigation, ui_settings, widgets</p><h3 id="_3-publishes-app-overrides" tabindex="-1">3. publishes (App Overrides) <a class="header-anchor" href="#_3-publishes-app-overrides" aria-label="Permalink to &quot;3. publishes (App Overrides)&quot;">​</a></h3><p><strong>Location</strong>: Published to <code>config/</code> via <code>php artisan vendor:publish --tag=modularity-config</code><br><strong>Loaded</strong>: Standard Laravel config loading</p><p>App-level overrides. Published files take precedence when merged.</p><p><strong>Common published configs</strong>: <code>config/modularity.php</code>, <code>config/modules.php</code>, <code>config/permission.php</code>, <code>config/auth.php</code></p><h3 id="_4-app-override-path" tabindex="-1">4. App Override Path <a class="header-anchor" href="#_4-app-override-path" aria-label="Permalink to &quot;4. App Override Path&quot;">​</a></h3><p><strong>Location</strong>: <code>base_path(&#39;modularity/*.php&#39;)</code><br><strong>Loaded</strong>: By <code>LoadLocalizedConfig</code> middleware when files exist</p><p>Optional app-specific config files that override deferred config.</p><h2 id="base-config" tabindex="-1">Base Config <a class="header-anchor" href="#base-config" aria-label="Permalink to &quot;Base Config&quot;">​</a></h2><p><strong>File</strong>: <code>config/config.php</code><br><strong>Key</strong>: <code>modularity</code> (via <code>$baseKey</code>)</p><p>Core package settings: app_url, admin paths, theme, enabled features, etc.</p><h2 id="currency-provider" tabindex="-1">Currency Provider <a class="header-anchor" href="#currency-provider" aria-label="Permalink to &quot;Currency Provider&quot;">​</a></h2><p><strong>Config</strong>: <code>modularity.currency_provider</code><br><strong>Env</strong>: <code>MODULARITY_CURRENCY_PROVIDER</code></p><p>Optional FQCN of a class implementing <code>CurrencyProviderInterface</code>. When null, Modularity uses <code>SystemPricingCurrencyProvider</code> if the SystemPricing module is present, else <code>NullCurrencyProvider</code>.</p><h2 id="paths" tabindex="-1">Paths <a class="header-anchor" href="#paths" aria-label="Permalink to &quot;Paths&quot;">​</a></h2><p><strong>Config</strong>: <code>modularity.paths</code> (from merges/paths.php)</p><p>Defines base paths for modules, vendor assets, and published resources.</p>',27),s=[i];function n(d,c,l,p,g,h){return a(),o("div",null,s)}const m=e(t,[["render",n]]);export{f as __pageData,m as default};
